import React from "react";

import ChatBox from "./components/ChatBox";
import Selects from "./components/seletorIAS";
import PerguntaResposta from "./components/PerguntaResposta";
import Header from "./header";

import { prepararPergunta } from "./utils/manipulacoesString";
import { chamarChatGPT, chamarGemini, chamarGrok, chamarDeepseek } from "./utils/APIchats";

import "./App.css";

export default function App() {

  const [IA1, setIA1] = React.useState("");
  const [IA2, setIA2] = React.useState("");
  const [arbitro, setarbitro] = React.useState("");

  const [pergunta, setPergunta] = React.useState("");
  const [resposta, setResposta] = React.useState("");
  const [respostaArbitro, setRespostaArbitro] = React.useState("")
  const [respostaPronta, setRespostaPronta] = React.useState(false)
  const [trocarVerdadeiro, settrocarVerdadeiro] = React.useState(false);
  const [respostaIA1, setRespostaIA1] = React.useState("")
  const [respostaIA2, setRespostaIA2] = React.useState("")
  const [prefixo, setPrefixo] = React.useState(
    "responda como se fosse um estudante do ensino médio Técnico de uma forma resumida que năo passe de 5 linhas sem gírias antigas, humanizado, sem girias e sem emojis esta seguinte pergunta: "
  );
  const [prefixoArbitro, setPrefixoArbitro] = React.useState("")

  let fia = []
  fia['Grok'] = (perguntaMontada, isArbiter) => chamarGrok(perguntaMontada, isArbiter)
  fia['Gemini'] = (perguntaMontada, isArbiter) => chamarGemini(perguntaMontada, isArbiter)
  fia['Chatgpt'] = (perguntaMontada, isArbiter) => chamarChatGPT(perguntaMontada, isArbiter)
  fia['deepseek'] = (perguntaMontada, isArbiter) => chamarDeepseek(perguntaMontada, isArbiter)

  async function chamarFuncaoPorNome(nome, perguntaPreparada) {
    if (nome != "") {
      let fSelect = fia[nome]
      let resp = await fSelect(perguntaPreparada, false);
      setRespostaArbitro(resp.resp)
      return resp.resp
    } else {
      alert("Por favor selecione todas as IAS")
    }

  }
  async function fluxoComunicacao() {
    let perguntaPreparada = prepararPergunta(pergunta, prefixo);
    setRespostaIA1(await chamarFuncaoPorNome(IA1, perguntaPreparada))
    setRespostaIA2(await chamarFuncaoPorNome(IA2, perguntaPreparada))
    setPrefixoArbitro(pergunta + " Resposta primeira IA: " + respostaIA1 + " Resposta segunda IA: " + respostaIA2 + " verifique se existe algum tipo de erro, alucinaçőes ou se faltam informaçőes nas respostas das IAs, faça uma pequena análise dos erros, que năo passe de 20 linhas")
    setRespostaArbitro(await chamarFuncaoPorNome(arbitro, prefixoArbitro))
  }


  console.log(prefixoArbitro)





  return (
    <div className="caixa">
      <Header />
      <div className="caixaPrincipal">

        <ChatBox
          resp={prefixoArbitro + respostaArbitro}
        />

        <Selects
          id=""
          IA1={IA1}
          IA2={IA2}
          arbitro={arbitro}
          trocarIA1={setIA1}
          trocarIA2={setIA2}
          trocarArbitro={setarbitro}
        />
      </div>
      <PerguntaResposta
        id=""
        quest={pergunta}
        answer={resposta}
        setquest={setPergunta}
        setanswer={setResposta}
        checkbox={trocarVerdadeiro}
        bloquearResposta={settrocarVerdadeiro}
        fluxoComunicacao={fluxoComunicacao}
      />
    </div>
  );
}
